import asyncio
from fastapi import APIRouter
from pydantic import BaseModel

router = APIRouter(prefix="/api/admin", tags=["admin"])


class RunRequest(BaseModel):
    message: str


class RunResponse(BaseModel):
    output: str
    error: str | None = None

\[EMAIL-REDACTED]("/run", response_model=RunResponse)
async def run_claude(req: RunRequest):
    try:
        proc = await asyncio.create_subprocess_exec(
            "claude", "--print", req.message,
            stdout=asyncio.subprocess.PIPE,
            stderr=asyncio.subprocess.PIPE,
            cwd="/home/gian/Projects/full-stack-feb/full-stack-feb",
        )
        stdout, stderr = await proc.communicate()
        return RunResponse(
            output=stdout.decode(),
            error=stderr.decode() if proc.returncode != 0 else None,
        )
    except FileNotFoundError:
        return RunResponse(output="", error="claude CLI not found on PATH")

import { useState } from "react";

interface Message {
  role: "user" | "assistant";
  text: string;
}

const API_URL = "http://localhost:8000/api/admin/run";

export default function AdminChat() {
  const [open, setOpen] = useState(false);
  const [input, setInput] = useState("");
  const [messages, setMessages] = useState<Message[]>([]);
  const [loading, setLoading] = useState(false);

  const send = async () => {
    const msg = input.trim();
    if (!msg || loading) return;
    setInput("");
    setMessages((m) => [...m, { role: "user", text: msg }]);
    setLoading(true);
    try {
      const res = await fetch(API_URL, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ message: msg }),
      });
      const data = await res.json();
      setMessages((m) => [
        ...m,
        { role: "assistant", text: data.error || data.output || "(empty)" },
      ]);
    } catch (e) {
      setMessages((m) => [
        ...m,
        { role: "assistant", text: `Error: ${e}` },
      ]);
    } finally {
      setLoading(false);
    }
  };

  if (!open) {
    return (
      <button onClick={() => setOpen(true)} style={bubbleStyle}>
        💬
      </button>
    );
  }

  return (
    <div style={panelStyle}>
      <div style={{ display: "flex", justifyContent: "space-between", padding: "8px 12px", borderBottom: "1px solid #333" }}>
        <strong>Admin</strong>
        <button onClick={() => setOpen(false)} style={{ background: "none", border: "none", color: "#fff", cursor: "pointer", fontSize: 18 }}>×</button>
      </div>
      <div style={{ flex: 1, overflow: "auto", padding: 12, display: "flex", flexDirection: "column", gap: 8 }}>
        {messages.map((m, i) => (
          <div key={i} style={{ alignSelf: m.role === "user" ? "flex-end" : "flex-start", background: m.role === "user" ? "#4a9eff" : "#333", padding: "6px 10px", borderRadius: 8, maxWidth: "85%", whiteSpace: "pre-wrap", fontSize: 13 }}>
            {m.text}
          </div>
        ))}
        {loading && <div style={{ color: "#888", fontSize: 13 }}>Running...</div>}
      </div>
      <div style={{ display: "flex", borderTop: "1px solid #333", padding: 8, gap: 8 }}>
        <input
          value={input}
          onChange={(e) => setInput(e.target.value)}
          onKeyDown={(e) => e.key === "Enter" && send()}
          placeholder="Message claude..."
          style={{ flex: 1, background: "#222", border: "1px solid #444", borderRadius: 6, padding: "6px 10px", color: "#fff", fontSize: 13 }}
        />
        <button onClick={send} disabled={loading} style={{ background: "#4a9eff", border: "none", borderRadius: 6, padding: "6px 12px", color: "#fff", cursor: "pointer" }}>
          Send
        </button>
      </div>
    </div>
  );
}

const bubbleStyle: React.CSSProperties = {
  position: "fixed",
  bottom: 20,
  right: 20,
  width: 48,
  height: 48,
  borderRadius: "50%",
  background: "#4a9eff",
  border: "none",
  fontSize: 22,
  cursor: "pointer",
  boxShadow: "0 2px 10px rgba(0,0,0,0.3)",
  zIndex: 9999,
};

const panelStyle: React.CSSProperties = {
  position: "fixed",
  bottom: 20,
  right: 20,
  width: 380,
  height: 480,
  background: "#1a1a1a",
  border: "1px solid #333",
  borderRadius: 12,
  display: "flex",
  flexDirection: "column",
  color: "#fff",
  zIndex: 9999,
  boxShadow: "0 4px 20px rgba(0,0,0,0.4)",
};

